import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    messages=[{
        "role": "user",
        "content": [
            {
                "type": "document",
                "source": {
                    "type": "base64",
                    "media_type": "application/pdf",
                    "data": encoded_pdf
                },
                "citations": {  # ← Enable Citations
                    "enabled": True
                }
            },
            {
                "type": "text",
                "text": "What were the key findings?"
            }
        ]
    }]
)

# Response includes:
response.content[0].text  # "The methodology used a randomized controlled trial design [p. 45]."
response.citations        # [{"cited_text": "...", "start_page_number": 45, ...}]

# ✅ Recommended
response = client.messages.create(
    messages=[{
        "content": [
            {
                "type": "document",
                "citations": {"enabled": True}  # ← Built-in Citations
            }
        ]
    }]
)

# ❌ Avoid
response = client.messages.create(
    messages=[{
        "content": [
            {
                "type": "text",
                "text": """
                First find the quotes from the document...
                [complex prompt with formatting rules]
                """
            }
        ]
    }]
)
